// Fetch conversation + agent using this.helpers.httpRequest
const items = $input.all();
const item = items[0];
const conversationId = item.json.body.conversation_id;
const apiKey = 'sk_733d2a2707d99f6bcdb9cc330570deea72390b20b6b2915e';

if (!conversationId) {
  return [{
    json: {
      error: true,
      errorCode: 'MISSING_CONVERSATION_ID',
      errorMessage: 'conversation_id is required in request body',
      webhookBody: item.json.body
    }
  }];
}

try {
  const conv = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.elevenlabs.io/v1/convai/conversations/${conversationId}`,
    headers: { 'xi-api-key': apiKey }
  });

  const agent = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.elevenlabs.io/v1/convai/agents/${conv.agent_id}`,
    headers: { 'xi-api-key': apiKey }
  });

  return [{
    json: {
      error: false,
      conversation: conv,
      agent: agent,
      webhookBody: item.json.body
    }
  }];
} catch (e) {
  const statusCode = e.response?.status || e.statusCode || 500;
  let errorMessage = e.message;

  if (statusCode === 404) {
    errorMessage = `Conversation not found: ${conversationId}`;
  } else if (statusCode === 401) {
    errorMessage = 'Invalid ElevenLabs API key';
  }

  return [{
    json: {
      error: true,
      errorCode: `ELEVENLABS_API_${statusCode}`,
      errorMessage: errorMessage,
      conversationId: conversationId,
      webhookBody: item.json.body
    }
  }];
}

const { conversation: conv, agent, webhookBody } = $json;

// ============================================================================
// COMPONENT A: CONVERSATION TRANSCRIPT RAW
// ============================================================================
let transcriptRaw = '';
if (Array.isArray(conv.transcript)) {
  transcriptRaw = conv.transcript
    .filter(t => t.message)
    .map(t => `${t.role.toUpperCase()}: ${t.message}`)
    .join('\n');
} else {
  transcriptRaw = conv.transcript || '';
}

if (!transcriptRaw || transcriptRaw.length === 0) {
  return {
    json: {
      error: true,
      errorCode: 'EMPTY_TRANSCRIPT',
      errorMessage: 'Conversation has no transcript data',
      conversationId: conv.conversation_id,
      agentId: conv.agent_id
    }
  };
}

// ============================================================================
// COMPONENT B: EXTRACTOR AGENT'S SYSTEM PROMPT
// ============================================================================
const agentSystemPrompt = agent.conversation_config?.agent?.prompt?.prompt || 'No agent prompt available';

// ============================================================================
// COMPONENT C: DESIRED RESPONSE STRUCTURED SCHEMA (field names and types)
// ============================================================================
// Use custom schema if provided, otherwise use the 22-field template
const defaultSchema = {
  "requestor": {
    "requestor_company_name": { "type": "string" },
    "requestor_first_name": { "type": "string" },
    "requestor_last_name": { "type": "string" }
  },
  "contact": {
    "contact_first_name": { "type": "string" },
    "contact_last_name": { "type": "string" },
    "contact_phone_number": { "type": "string" },
    "contact_preferred_followup_channel": { "type": "string" },
    "contact_preferred_followup_time": { "type": "string" },
    "requested_service_address": { "type": "string" },
    "requestor_is_contact": { "type": "boolean" }
  },
  "request": {
    "existing_request": { "type": "boolean" },
    "request_affected_asset": { "type": "string" },
    "request_deadline": { "type": "string" },
    "request_description": { "type": "string" },
    "request_summary": { "type": "string" }
  },
  "routing": {
    "conversation_transfer_destination": { "type": "string" },
    "conversation_transfer_reason": { "type": "string" },
    "conversation_transferred": { "type": "boolean" },
    "requestor_requested_specific_person": { "type": "string" },
    "routing_department": { "type": "string" },
    "routing_site_location": { "type": "string" },
    "routing_urgency": { "type": "string" }
  }
};

const responseSchema = webhookBody.extraction_schema || defaultSchema;

// ============================================================================
// COMPONENT D: MULTI-PROMPT JSON TEMPLATE (detailed extraction instructions)
// ============================================================================
const extractionInstructions = {
  "requestor": {
    "requestor_company_name": {
      "type": "string",
      "description": "Extract requestor's employer/company name from self-identification phrases. Valid triggers: 'I'm with...', 'calling from...', 'I work for...'. Critical exclusions: (a) Never extract service provider name from agent greeting, (b) Ignore company being called. Return null when no company affiliation stated."
    },
    "requestor_first_name": {
      "type": "string",
      "description": "Extract first name of person calling from self-introduction. Target phrases: 'This is [name]', 'My name is [name]'. Extract ONLY first name component. Return null if no first name provided."
    },
    "requestor_last_name": {
      "type": "string",
      "description": "Extract ONLY last name of person calling. Exclude first names, titles/honorifics. Capture compound surnames completely (e.g., 'De La Vega'). Return null when no last name provided."
    }
  },
  "contact": {
    "contact_first_name": {
      "type": "string",
      "description": "Extract first name of person designated for follow-up. Default: same as requestor_first_name. Override only when requestor explicitly designates alternate contact."
    },
    "contact_last_name": {
      "type": "string",
      "description": "Extract last name of person designated for follow-up. Default: same as requestor's last name."
    },
    "contact_phone_number": {
      "type": "string",
      "description": "Extract final confirmed callback phone number in E.164 format (+1XXXXXXXXXX). If user corrected a number, use correction only. Convert number words to digits. Return null if count < 10 digits or no number found."
    },
    "contact_preferred_followup_channel": {
      "type": "string",
      "description": "Valid values: phone, sms, email. Detection triggers: 'call me', 'text me', 'send me an email'. Default to 'phone' when unclear."
    },
    "contact_preferred_followup_time": {
      "type": "string",
      "description": "Extract follow-up timing preferences. Examples: 'tomorrow afternoon', 'after 6 PM only', 'weekdays before noon'. Return null when none mentioned."
    },
    "requested_service_address": {
      "type": "string",
      "description": "Extract physical location WHERE WORK HAPPENS (dispatch destination). NOT the branch being contacted. Return null if no dispatch required or requestor coming to company location."
    },
    "requestor_is_contact": {
      "type": "boolean",
      "description": "Is requestor the designated contact for follow-up? Default: TRUE. Set FALSE only when requestor makes explicit statement designating alternate contact."
    }
  },
  "request": {
    "existing_request": {
      "type": "boolean",
      "description": "Is this regarding an existing request/ticket? Detection: reference to case/ticket numbers, 'following up on', 'checking status of'. Default FALSE when unclear."
    },
    "request_affected_asset": {
      "type": "string",
      "description": "Extract specific equipment, device, software, or system involved. Include model numbers, asset IDs if stated. Return null when no specific asset mentioned."
    },
    "request_deadline": {
      "type": "string",
      "description": "Extract requestor-specified date or timeframe. Examples: 'need this fixed by Friday', 'within 48 hours'. Return null when none mentioned."
    },
    "request_description": {
      "type": "string",
      "description": "Generate single factual paragraph (80-120 words) using ONLY explicitly stated information. Inverted-pyramid format. Plain language, active voice. No future commitments."
    },
    "request_summary": {
      "type": "string",
      "description": "Generate precise ticket title (<80 chars). Format: '[Equipment/Issue] - [Location]'. Avoid generic terms like 'issue', 'problem'. Include equipment ID if provided."
    }
  },
  "routing": {
    "conversation_transfer_destination": {
      "type": "string",
      "description": "If transferred, capture destination label. Examples: 'Main operator', 'Billing department'. Return null if no transfer."
    },
    "conversation_transfer_reason": {
      "type": "string",
      "description": "Short summary (≤120 chars) explaining WHY transferred. Return null if no transfer."
    },
    "conversation_transferred": {
      "type": "boolean",
      "description": "Was conversation transferred to live person? Set TRUE only when actual transfer mechanism invoked. Default FALSE."
    },
    "requestor_requested_specific_person": {
      "type": "string",
      "description": "Name of specific person requestor asks to speak with. Return null if no specific person requested by name."
    },
    "routing_department": {
      "type": "string",
      "description": "EXACTLY one from: Service, Field Service, Sales, Marketing, Purchasing, Fulfillment, Shipping, Billing, Finance, Accounting, HR, Payroll, IT, IT Support, Operations, Contracts, Administration, General. Default 'General' when unclear."
    },
    "routing_site_location": {
      "type": "string",
      "description": "Site or branch location for internal routing. Return null if none mentioned."
    },
    "routing_urgency": {
      "type": "string",
      "description": "Valid values: emergency (safety/critical), soon (needs quick attention), routine (standard), estimate (quote only). Default 'routine' when unclear."
    }
  }
};

// Allow override from webhook body
const fieldInstructions = webhookBody.extraction_instructions || extractionInstructions;

// ============================================================================
// COMPONENT E: AGENT CONFIGURATION SPECIFICATION (full agent config)
// ============================================================================
const agentConfig = {
  agent_id: agent.agent_id,
  name: agent.name,
  conversation_config: agent.conversation_config,
  platform_settings: agent.platform_settings,
  metadata: agent.metadata
};

// ============================================================================
// ASSEMBLE THE 5-COMPONENT BULK PROMPT
// ============================================================================
const bulkPrompt = `You are a precision data extraction system. Your task is to extract structured fields from a voice call transcript.

================================================================================
COMPONENT A: CONVERSATION TRANSCRIPT (RAW)
================================================================================
${transcriptRaw}

================================================================================
COMPONENT B: AGENT SYSTEM PROMPT (Context for understanding agent behavior)
================================================================================
${agentSystemPrompt}

================================================================================
COMPONENT C: RESPONSE SCHEMA (Required output structure)
================================================================================
${JSON.stringify(responseSchema, null, 2)}

================================================================================
COMPONENT D: EXTRACTION INSTRUCTIONS (Field-level micro-prompts)
================================================================================
${JSON.stringify(fieldInstructions, null, 2)}

================================================================================
COMPONENT E: AGENT CONFIGURATION (Full agent specification)
================================================================================
${JSON.stringify(agentConfig, null, 2)}

================================================================================
EXTRACTION TASK
================================================================================
Using the transcript (A), agent context (B, E), and the detailed extraction instructions (D), extract all fields defined in the schema (C).

RULES:
1. Use null for any field that cannot be determined from the transcript
2. Follow the exact type specifications (string, boolean)
3. Apply the micro-prompt instructions in Component D precisely
4. Return ONLY valid JSON matching the schema structure
5. Do not add explanations or commentary - return pure JSON

OUTPUT: Return the extracted data as a JSON object with the exact structure from Component C.`;

// Build Gemini request body
const geminiBody = JSON.stringify({
  contents: [{ parts: [{ text: bulkPrompt }] }],
  generationConfig: { 
    temperature: 0.1, 
    responseMimeType: 'application/json' 
  }
});

return {
  json: {
    error: false,
    bulkPrompt: bulkPrompt,
    geminiBody: geminiBody,
    conversationId: conv.conversation_id,
    agentId: conv.agent_id,
    agentName: agent.name,
    transcriptLength: transcriptRaw.length,
    schemaFieldCount: Object.keys(fieldInstructions).reduce((acc, section) => acc + Object.keys(fieldInstructions[section]).length, 0),
    components: {
      A_transcript: true,
      B_agentPrompt: true,
      C_responseSchema: true,
      D_extractionInstructions: true,
      E_agentConfig: true
    }
  }
};

const prev = $('Assemble 5-Component Bulk Prompt').item.json;
const response = $json;
let extracted = {};

try {
  const text = response.candidates[0].content.parts[0].text;
  extracted = JSON.parse(text);
} catch(e) {
  extracted = { error: 'Parse failed', raw: response };
}

return {
  json: {
    success: true,
    conversation_id: prev.conversationId,
    agent_id: prev.agentId,
    agent_name: prev.agentName,
    extracted_fields: extracted,
    model: 'gemini-3-pro',
    architecture: '5-component-bulk-prompt',
    components_used: prev.components,
    schema_field_count: prev.schemaFieldCount,
    transcript_chars: prev.transcriptLength,
    timestamp: new Date().toISOString()
  }
};
